def dfs_topo_sort(graph, num_nodes):
    """
    DFS 后序逆序实现拓扑排序
    """
    visited = [False] * num_nodes
    rec_stack = [False] * num_nodes  # 用于检测环
    result = []

    def dfs(u):
        visited[u] = True
        rec_stack[u] = True

        for v in graph.get(u, []):
            if not visited[v]:
                if not dfs(v):
                    return False  # 发现环
            elif rec_stack[v]:
                return False  # 发现回边，存在环

        rec_stack[u] = False
        result.append(u)  # 后序位置记录
        return True

    for i in range(num_nodes):
        if not visited[i]:
            if not dfs(i):
                raise ValueError("图中存在环，无法进行拓扑排序")

    return result[::-1]  # 逆序得到拓扑排序结果

# 同上图示例
graph = {0: [1, 2], 1: [3], 2: [3], 3: []}
print(dfs_topo_sort(graph, 4))  # 输出拓扑序列

def topo_sort_with_level(graph, num_nodes):
    """
    带层级的拓扑排序：可用于计算最长路径/关键路径
    同时返回每个节点的拓扑层级
    """
    from collections import deque

    in_degree = [0] * num_nodes
    for u in range(num_nodes):
        for v in graph.get(u, []):
            in_degree[v] += 1

    queue = deque()
    level = [0] * num_nodes
    for i in range(num_nodes):
        if in_degree[i] == 0:
            queue.append(i)

    while queue:
        u = queue.popleft()
        for v in graph.get(u, []):
            in_degree[v] -= 1
            # 更新层级：当前节点层级 + 1
            level[v] = max(level[v], level[u] + 1)
            if in_degree[v] == 0:
                queue.append(v)

    return level  # level[i] 表示以 i 结尾的最长路径长度

# 示例：计算关键路径长度
graph = {0: [1, 2], 1: [3], 2: [3], 3: [4], 4: []}
print(topo_sort_with_level(graph, 5))  # [0, 1, 1, 2, 3]
